sql:
SELECT import_id, import_data
FROM data_imports
WHERE status = 'failed';

external_knowledge:
- "cinematic treasures" refers to movies;
- "crossed the great ocean to the land of freedom" refers to the movie being released in the United States (region_id = 1);
- "maiden voyages" refers to the release dates of the movies;
- "treasures they accumulated in the land of the free" refers to the total earnings of the movies in the United States.

sql:
SELECT DISTINCT title 
FROM movies 
WHERE genre = 'Horror' AND rating = 'R';

external_knowledge:
'From the turn of the millennium' refers to the period from 2000 to 2010;
'Films that managed to rake in the most cash globally' implies movies with the highest worldwide earnings;
'Total earnings' is the sum of worldwide box office earnings for each movie.

- High-grossing films: movies with significant financial success;
- Launch date: the date when the movie was first made available to the public;
- Global earnings: the total revenue generated from the box office across the world.

sql:
SELECT COUNT(movie_id) 
FROM movie_genres 
WHERE genre_name = 'Adventure';
